import { prisma } from "@/lib/db";
import { Plus, Search, MapPin, Globe, Award } from "lucide-react";
import Link from "next/link";

export const dynamic = 'force-dynamic';

async function getBrands() {
    return await prisma.brand.findMany({
        include: {
            country: true,
            _count: {
                select: { products: true }
            }
        },
        orderBy: { name: 'asc' }
    });
}

export default async function BrandsPage() {
    const brands = await getBrands();

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            {/* Header */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                    <h1 className="text-4xl font-bold text-gray-900 tracking-tight mb-2">Brands</h1>
                    <p className="text-gray-500">Manage manufacturers and product brands.</p>
                </div>
                <button className="bg-emerald-600 text-white px-6 py-3 rounded-xl font-semibold shadow-lg hover:shadow-emerald-900/20 hover:-translate-y-0.5 transition-all flex items-center gap-2">
                    <Plus size={20} />
                    <span>Add New Brand</span>
                </button>
            </div>

            {/* Content */}
            <div className="card-premium p-6">
                {/* Filter Header */}
                <div className="flex justify-between items-center mb-6 pb-4 border-b border-gray-100">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                        <input
                            type="text"
                            placeholder="Search brands..."
                            className="pl-10 pr-4 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:border-emerald-500 w-64 transition-all"
                        />
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {brands.length === 0 ? (
                        <div className="col-span-full py-12 text-center text-gray-400">
                            <p>No brands found.</p>
                        </div>
                    ) : (
                        brands.map((brand) => (
                            <div key={brand.id} className="group border border-gray-100 rounded-2xl p-6 hover:shadow-lg transition-all bg-white relative overflow-hidden">
                                <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                                    <Award size={64} />
                                </div>

                                <div className="flex justify-between items-start mb-4">
                                    <div className="w-12 h-12 rounded-xl bg-gray-50 flex items-center justify-center text-xl font-bold text-gray-700 uppercase">
                                        {brand.logo ? (
                                            <img src={brand.logo} alt={brand.name} className="w-full h-full object-cover rounded-xl" />
                                        ) : (
                                            brand.name.substring(0, 2)
                                        )}
                                    </div>
                                    <div className="flex items-center gap-1 text-xs font-semibold bg-blue-50 text-blue-600 px-2 py-1 rounded-lg">
                                        <BoxIcon size={12} />
                                        {brand._count.products} products
                                    </div>
                                </div>

                                <h3 className="text-lg font-bold text-gray-900 mb-1">{brand.name}</h3>

                                {brand.country && (
                                    <div className="flex items-center gap-1.5 text-sm text-gray-500">
                                        <Globe size={14} className="text-gray-400" />
                                        <span>{brand.country.name}</span>
                                        <span className="text-xs text-gray-300">({brand.country.code})</span>
                                    </div>
                                )}
                            </div>
                        ))
                    )}
                </div>
            </div>
        </div>
    );
}

function BoxIcon({ size }: { size: number }) {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"></path><polyline points="3.27 6.96 12 12.01 20.73 6.96"></polyline><line x1="12" y1="22.08" x2="12" y2="12"></line></svg>
    )
}
